proof:
have h_cofix_eq : Coalg.toCofix a = Coalg.toCofix b := by
  have := congrArg StateCofixFinal.toCofix ( Quot.sound h_bisim );
  convert this using 1;
have h_map_eq : ∀ (c : Coalg F α), (TypeVec.id ::: fun init => ofLarge (Quot.mk Coalg.Bisim { σ := c.σ, dest' := c.dest', s := init })) <$$> c.dest' c.s = (TypeVec.id ::: (ofLarge ∘ StateCofixFinal.ofCofix)) <$$> Cofix.dest (Coalg.toCofix c) := by
                                                                                                intro c
                                                                                                simp [Coalg.toCofix, Cofix.dest_corec];
                                                                                                rw [ MvFunctor.map_map ];
                                                                                                congr! 2;
                                                                                                ext i; simp [TypeVec.appendFun];
                                                                                                cases i <;> simp +decide [ splitFun ];
                                                                                                · exact ( StateCofixFinal.ofCofix_toCofix ( Quot.mk _ ( Coalg.corec c.dest' _ ) ) ).symm ▸ rfl;
                                                                                                · rfl;
rw [ h_map_eq a, h_map_eq b, h_cofix_eq ]

